from dataclasses import dataclass
from typing import Optional


@dataclass
class Config:
    host: str
    port: int
    ssl: bool = False
    pool_size: int = 10


def fetch_config(env: str = "production") -> Config:
    """Load database configuration for the given environment."""
    if env == "test":
        return Config(host="localhost", port=5433, ssl=False)
    return Config(host="db.local", port=5432, ssl=True)


def get_connection_string(config: Config) -> str:
    proto = "postgresql+ssl" if config.ssl else "postgresql"
    return f"{proto}://{config.host}:{config.port}"

