from src.config_loader import fetch_config


def connect_db():
    config = fetch_config()
    conn_str = f"postgresql://{config['host']}:{config['port']}"
    return create_connection(conn_str)


def create_connection(conn_str: str):
    return {"connection": conn_str, "active": True}
